import{_ as a,o as r,c as i,ae as n}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"Xamarin & MAUI Overview","description":"","frontmatter":{"title":"Xamarin & MAUI Overview","slug":"xamarin-maui-sdk-overview"},"headers":[],"relativePath":"developer-hub/xamarin-maui-sdk-overview.md","filePath":"developer-hub/xamarin-maui-sdk-overview.md"}'),t={name:"developer-hub/xamarin-maui-sdk-overview.md"};function o(s,e,h,u,c,p){return r(),i("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Whether you&#39;ve built your application using Xamarin or MAUI, Branch can seamlessly integrate into your codebase so you can start using powerful features like deep linking and attribution in your marketing campaigns.</p><p>The steps to configure an application to work with the Branch SDK differ based on whether you are using <a href="./xamarin-configuration.html">Xamarin</a> or <a href="./maui-configuration.html">MAUI</a>, and whether you are building for iOS or Android.</p><p>However, the Branch NuGet package you will use is the same regardless of the platform you&#39;re on. This <a href="https://www.nuget.org/packages/Branch-Xamarin-Linking-SDK" target="_blank" rel="noreferrer">package</a> is called <code>Branch-Xamarin-Linking-SDK</code>, and versions 9.0.0+ are for MAUI apps while older versions are for Xamarin apps.</p><p>Once you&#39;ve configured your application and initialized the Branch SDK, the code for implementing features is the same whether you are using Xamarin or MAUI. These features include things like creating Branch Deep Links or tracking Branch Events.</p><h2 id="github-repo" tabindex="-1">GitHub Repo <a class="header-anchor" href="#github-repo" aria-label="Permalink to &quot;GitHub Repo&quot;">​</a></h2><p>Open-source GitHub repository: <a href="https://github.com/BranchMetrics/xamarin-branch-deep-linking-attribution" target="_blank" rel="noreferrer">https://github.com/BranchMetrics/xamarin-branch-deep-linking-attribution</a></p>',7)])])}const m=a(t,[["render",o]]);export{d as __pageData,m as default};
